class Controls{#dir={left:!1,right:!1,up:!1,down:!1,forward:!1,backward:!1};constructor(){this.#keyDownEvtListener(),this.#keyUpEvtListener()}#keyDownEvtListener(){document.addEventListener("keydown",(e=>{switch(e.key){case"ArrowLeft":return void(this.#dir.left=!0);case"ArrowRight":return void(this.#dir.right=!0)}}))}#keyUpEvtListener(){document.addEventListener("keyup",(e=>{switch(e.key){case"ArrowLeft":return void(this.#dir.left=!0);case"ArrowRight":return void(this.#dir.right=!0)}}))}}export{Controls};